static inline uint64_t pbvh_accel_floor_um_per_tick2(uint32_t hz) {
    uint64_t h = (uint64_t)(hz > 0u ? hz : 1u);
    uint64_t d = 2ull * h * h;
    return (1400000ull + d - 1ull) / d;
}

